// Ações são os "eventos" do seu app
type CartEvent =
  | { type: 'ITEM_ADDED'; product: Product; qty: number }
  | { type: 'ITEM_REMOVED'; productId: string }
  | { type: 'CART_CLEARED' };

// Reducer é o "event handler" central
function cartReducer(state: CartState, event: CartEvent): CartState {
  switch (event.type) {
    case 'ITEM_ADDED':
      return { ...state, items: [...state.items, { ...event.product, qty: event.qty }] };
    case 'ITEM_REMOVED':
      return { ...state, items: state.items.filter(i => i.id !== event.productId) };
    case 'CART_CLEARED':
      return { ...state, items: [] };
  }
}

// Componente emite eventos via dispatch
function AddToCartButton({ product }: { product: Product }) {
  const dispatch = useCartDispatch(); // Context
  return (
    <button onClick={() => dispatch({ type: 'ITEM_ADDED', product, qty: 1 })}>
      Adicionar
    </button>
  );
}

import { create } from 'zustand';
import { subscribeWithSelector } from 'zustand/middleware';

const useCartStore = create(
  subscribeWithSelector<CartState>((set) => ({
    items: [],
    addItem: (product: Product) =>
      set((s) => ({ items: [...s.items, product] })),
  }))
);

// Side-effects reativos - equivalente a "listeners"
// Analytics reage automaticamente quando items muda
useCartStore.subscribe(
  (state) => state.items,
  (items, prevItems) => {
    if (items.length > prevItems.length) {
      const added = items[items.length - 1];
      analytics.track('item_added', { product: added.id });
    }
  }
);

// Componente fica limpo - só lê estado
function CartBadge() {
  const count = useCartStore((s) => s.items.length);
  return <Badge>{count}</Badge>;
}

import { createMachine, assign } from 'xstate';
import { useMachine } from '@xstate/react';

// Eventos tipados definem o que pode acontecer
type CheckoutEvent =
  | { type: 'NEXT' }
  | { type: 'BACK' }
  | { type: 'SUBMIT' }
  | { type: 'PAYMENT_SUCCESS' }
  | { type: 'PAYMENT_ERROR'; error: string };

const checkoutMachine = createMachine({
  id: 'checkout',
  initial: 'cart',
  states: {
    cart:     { on: { NEXT: 'shipping' } },
    shipping: { on: { NEXT: 'payment', BACK: 'cart' } },
    payment:  { on: {
      SUBMIT: 'processing',
      BACK: 'shipping'
    }},
    processing: { on: {
      PAYMENT_SUCCESS: 'success',
      PAYMENT_ERROR: 'payment'
    }},
    success: { type: 'final' }
  }
});

function Checkout() {
  const [state, send] = useMachine(checkoutMachine);

  // Cada evento é type-safe - impossível enviar evento inválido
  return (
    <div>
      {state.matches('cart') && <Cart onNext={() => send({ type: 'NEXT' })} />}
      {state.matches('shipping') && <Shipping onNext={() => send({ type: 'NEXT' })} />}
      {state.matches('payment') && <Payment onSubmit={() => send({ type: 'SUBMIT' })} />}
      {state.matches('processing') && <Spinner />}
      {state.matches('success') && <ThankYou />}
    </div>
  );
}
